#include <debugging>
#include <print>
#include <cstdlib>
#include <string_view>

// Debug check: pause in debugger if attached, abort otherwise
void debug_assert(bool condition, std::string_view msg) {
    if (!condition) {
        std::println(stderr, "Assertion failed: {}", msg);
        std::breakpoint_if_debugging(); // no-op without a debugger
        std::abort();
    }
}

int main() {
    // Normal run: breakpoint_if_debugging() is a no-op,
    // then abort() would terminate with the message above.
    // Debug session: execution pauses on the breakpoint line.
    debug_assert(1 + 1 == 2, "basic arithmetic"); // passes
    // debug_assert(false, "test"); // uncomment to demonstrate
}

#include <debugging>
#include <print>
#include <vector>
#include <string_view>

struct Request {
    int id;
    std::string_view path;
};

void handle(const Request& req) {
    // Detailed tracing only when a debugger is attached —
    // this branch is never taken in production.
    if (std::is_debugger_present()) {
        std::println(stderr, "[trace] handle(): id={} path={}",
                     req.id, req.path);
    }

    if (req.path.empty()) {
        std::println(stderr, "[error] empty request path (id={})", req.id);
        // Give the debugger a chance to inspect the stack before terminating
        std::breakpoint_if_debugging();
        std::abort();
    }

    std::println("OK: {}", req.path);
}

int main() {
    std::vector<Request> requests = {
        {1, "/api/users"},
        {2, "/api/orders"},
    };

    for (const auto& r : requests) {
        handle(r);
    }
}

