// AFTER (C++26, portable):
#include <string>
#include <cstdlib>   // mbstowcs (POSIX/C standard)
#include <cwchar>

// Example platform replacement (POSIX):
void narrow_to_wide_example() {
    const char* narrow = "hello";
    std::mbstate_t state{};
    std::size_t len = std::mbsrtowcs(nullptr, &narrow, 0, &state) + 1;
    std::wstring wide(len, L'\0');
    std::mbsrtowcs(wide.data(), &narrow, len, &state);
    // wide now contains L"hello"
}

// For C++26: std::text_encoding (Module 7) — encoding detection
// For actual byte conversion: ICU, simdutf, or OS API

#include <atomic>
#include <thread>

// BAD: volatile is NOT atomic
// (and compound ops are removed in C++26)
// volatile int shared_counter = 0;
// shared_counter += 1; // COMPILE ERROR in C++26

// GOOD: std::atomic provides real atomicity
std::atomic<int> shared_counter{0};

void increment_relaxed() {
    // Explicit memory order — maximum performance
    shared_counter.fetch_add(1, std::memory_order_relaxed);
}

void increment_sequentially_consistent() {
    // operator+= on atomic uses seq_cst by default
    shared_counter += 1;
}

// shared_ptr::unique() is also removed — use use_count():
#include <memory>

void migrate_unique() {
    auto ptr = std::make_shared<int>(42);

    // BEFORE (C++23):
    // if (ptr.unique()) { /* ... */ }  // ERROR in C++26

    // AFTER:
    if (ptr.use_count() == 1) {
        // Sole owner — but in MT code this is still racy!
        *ptr = 100;
    }
}

